protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexing is managed via the container's indexing policy,
    // not EF Core. In EF Core 9 HasIndex throws InvalidOperationException for Cosmos entities.

    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve EF Core 8 discriminator property name ("Discriminator" → not the new "$type" default)
    // so existing documents and direct SQL queries (c.Discriminator) remain compatible.
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve EF Core 8 compound id format ("Product|123") so FindAsync/point-reads
    // still match the 500K existing documents written by EF Core 8.
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

