using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports sync I/O — use async throughout.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still valid because we configured HasDiscriminator("Discriminator")
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

